const fs = require\('fs'\);
const path = require\('path'\);

function analyzeCSV\(file, label\) {
  const csv = fs.readFileSync\(path.join\('public/dummy-data', file\), 'utf-8'\);
  const lines = csv.split\('\\n'\).filter\(l => l.trim\(\)\);
  const headers = lines[0].split\(','\);
  const rows = lines.slice\(1\).map\(l => l.split\(','\)\);

  console.log\('\\\\n' + '═'.repeat\(60\)\);
  console.log\(label\);
  console.log\('═'.repeat\(60\)\);
  console.log\('행 수:', rows.length\);
  console.log\('열 수:', headers.length\);
  console.log\('컬럼:', headers.join\(', '\)\);

  // 결측치 비율
  let missing = 0, total = 0;
  for \(const row of rows\) {
    for \(const val of row\) {
      total++;
      if \(val === ''\) missing++;
    }
  }
  console.log\('결측치:', missing, '/', total, '\(' + \(missing/total*100\).toFixed\(2\) + '%\)'\);

  // group_id 확인 \(Dataset 2\)
  const gidIdx = headers.indexOf\('group_id'\);
  if \(gidIdx >= 0\) {
    const groups = new Set\(rows.map\(r => r[gidIdx]\)\);
    console.log\('팀 수:', groups.size\);
    // 팀별 크기
    const sizes = {};
    rows.forEach\(r => { sizes[r[gidIdx]] = \(sizes[r[gidIdx]]||0\)+1; }\);
    console.log\('팀 크기 범위:', Math.min\(...Object.values\(sizes\)\), '~', Math.max\(...Object.values\(sizes\)\)\);
  }

  // 값 범위 확인 \(첫 측정변수\)
  const vals = rows.map\(r => Number\(r[0]\)\).filter\(v => !isNaN\(v\) && v !== 0\);
  console.log\('첫 변수\(' + headers[0] + '\) 범위:', Math.min\(...vals\), '~', Math.max\(...vals\)\);
  console.log\('평균:', \(vals.reduce\(\(a,b\)=>a+b,0\)/vals.length\).toFixed\(3\)\);
}

analyzeCSV\('dataset1_moderated_mediation.csv', 'Dataset 1: 조절된 매개모형'\);
analyzeCSV\('dataset2_hlm_multilevel.csv', 'Dataset 2: HLM 다층분석'\);
analyzeCSV\('dataset3_scale_validation.csv', 'Dataset 3: 척도개발·타당화'\);
")
